// handler result, no generic enum crossing, no dispatch on a dynamic value on the covered plane. Node
// results are typed struct cells; a relation child reads the parent's REAL struct result via
// direct field access (child-present decision from the real parent value — relationSingle /
// connection converge). A real-concurrency stage (bc#87) is static parallel orchestration —
// scoped worker threads (bounded by the static plan.concurrency) call the concrete node_*
// method; preflight + interpret are committed in ascending index order so the value / op
// multiset / failure precedence byte-match run_behavior. The output is a typed struct/value
// assembled by struct literal + field access — the consumer keeps it native.
pub fn run_native_raw_struct_NestedCreate<H: HandlerNRNestedCreate>(
    handlers: &H,
    in_: InNRNestedCreate,
) -> Result<T2, BehaviorError> {
    let cell_tx_body_0: RefCell<T0> = RefCell::new(Default::default());
    let produced_tx_body_0 = std::cell::Cell::new(false);
    let _ = &produced_tx_body_0;
    let cell_tx_body_1: RefCell<T1> = RefCell::new(Default::default());
    let produced_tx_body_1 = std::cell::Cell::new(false);
    let _ = &produced_tx_body_1;
    // ── op 'tx_body_0' (Insert) ──
    let ports_tx_body_0 = PortsNRNestedCreateTxBody0 { f_sql: "INSERT INTO benchmark_users (email, name) VALUES ($1, $2) RETURNING id".to_string(), f_p0: in_.email.clone(), f_p1: in_.name.clone() };
    let row_tx_body_0 = match handlers.node_tx_body_0(&ports_tx_body_0, None) {
        Some(r) => r,
        None => return Err(unknown_component("Insert")),
    };
    if row_tx_body_0.is_error {
        return Err(BehaviorError::new("OP_FAILED", format!("operation '{}' failed under 'fail' policy: {}", "tx_body_0", row_tx_body_0.err)));
    }
    *cell_tx_body_0.borrow_mut() = T0 { id: row_tx_body_0.id };
    produced_tx_body_0.set(true);
    // ── op 'tx_body_1' (Insert, parent:tx_body_0) ──
    if produced_tx_body_0.get() {
        let ports_tx_body_1 = PortsNRNestedCreateTxBody1 { f_sql: "INSERT INTO benchmark_posts (author_id, title) VALUES ($1, $2) RETURNING id, author_id, title".to_string(), f_p0: cell_tx_body_0.borrow().id, f_p1: in_.title.clone() };
        let row_tx_body_1 = match handlers.node_tx_body_1(&ports_tx_body_1, None) {
            Some(r) => r,
            None => return Err(unknown_component("Insert")),
        };
        if row_tx_body_1.is_error {
            return Err(BehaviorError::new("OP_FAILED", format!("operation '{}' failed under 'fail' policy: {}", "tx_body_1", row_tx_body_1.err)));
        }
        *cell_tx_body_1.borrow_mut() = T1 { id: row_tx_body_1.id, author_id: row_tx_body_1.author_id, title: row_tx_body_1.title };
        produced_tx_body_1.set(true);
    }
    let __out = T2 { user: cell_tx_body_0.borrow().clone(), post: cell_tx_body_1.borrow().clone() };
    Ok(__out)
}

